// Получаем текст из предыдущего узла. 
// Замените 'text' на название поля, в котором лежит ответ нейросети
const aiResponse = items[0].json.output || ""; 

// Регулярное выражение для поиска содержимого внутри тегов <seed>
// Флаг 'g' - искать все совпадения, 's' - учитывать переносы строк
const seedRegex = /<seed>(.*?)<\/seed>/gs;

let seeds = [];
let match;

// Ищем все совпадения в цикле
while ((match = seedRegex.exec(aiResponse)) !== null) {
    // Чистим результат от лишних пробелов и добавляем в массив
    const cleanSeed = match[1].trim();
    if (cleanSeed) {
        seeds.push({ seed: cleanSeed });
    }
}

// Если нужно просто вернуть массив строк для сохранения в файл, раскомментируйте нижнюю строку:
// return [{ json: { all_seeds: seeds.map(s => s.seed).join('\n') } }];

// Возвращаем результат в формате n8n (один сид = один элемент)
return seeds.map(s => ({ json: s }));
